export const sar2_how_do_we_measure = ["Students enrolled in their final year at FE colleges achieving regulated level 2 qualifications."];
export const sar2_source_name = ["Further education college statistics"];
export const sar2_source_url = ["https://www.economy-ni.gov.uk/articles/further-education-college-statistics"];
export const sar2_further_information = ["The information presented in this table has been derived from Consolidated Data return (CDR) provided by FE colleges. Each of the data returns are computerised data files consisting of individual records for each enrolment recorded by FE colleges during each academic year. Figures are correct as of the 13th of October 2023.\r\n\r\nIndividual students are identified using student ID within each college and each academic year. Students can achieve a qualification in more than one course. \r\n\r\nOnly students enrolled in their final year on regulated level 2 courses are included in this analysis. Those in their final year, who have completed the course and subsequently achieved are regarded as “Students achieving qualifications”. \r\n\r\nTo prevent the identification of individuals, figures in the attached tables are rounded to the nearest 5, with 0, 1, 2 rounded to 0.\r\n\r\nFrom academic year 2013/14, ‘regulated enrolments’ at ‘level 3 or below’ are regarded as those on courses that are at and appear on the Register of Regulated Qualifications (RRQ), which contains qualifications on both the Qualifications and Credit Framework and the National Qualifications Framework or part of the Department’s Prescribed List of Approved Qualifications (PLAQ)/Access list).\r\n\r\n“Level” refers to the nationally recognised qualification level of the course.\r\n\r\nAchievements are final year full and partial achievements.\r\n\r\nTransfers are excluded from the analysis.\r\n\r\nWithdrawals are included where there is an achieved outcome.\r\n\r\nIn 2020/21, 2021/22 and 2022/23, where the Outcome code is ‘S’ (COVID affected - outcome deferred to next year), these enrolments are filtered out of all performance analysis, that is Students enrolled in final year and Students achieving qualifications.\r\n\r\nDue to rounding the sum of numbers in each row or column may not match the total shown.\r\n\r\nPercentages are based on unrounded figures and are suppressed if a figure is less than 22.5. Percentages have been rounded to the nearest integer."];
export const sar2_metadata = {dataset : "sar2", table_code : "SARQL2FEEQ", years : "2019/20 - 2022/23", start_year : "2019/20", end_year : "2022/23", geog_level : "ni", dataset_url : "https://data.nisra.gov.uk/table/SARQL2FEEQ", name : "Department for the Economy", id : "EQGRP", email : "dfemail@economy-ni.gov.uk", subject : "Further education", product : "Achievements", title : "Students achieving regulated qualifications at level 2 in further education colleges", note : "Students achieving regulated qualifications at level 2 in further education (FE) colleges\r\n\r\nHow do we measure this?\r\nStudents enrolled in their final year at FE colleges achieving regulated level 2 qualifications.\r\n\r\nSource\r\n[url=https://www.economy-ni.gov.uk/articles/further-education-college-statistics]Further education college statistics[/url]\r\n\r\nFurther information\r\nThe information presented in this table has been derived from Consolidated Data return (CDR) provided by FE colleges. Each of the data returns are computerised data files consisting of individual records for each enrolment recorded by FE colleges during each academic year. Figures are correct as of the 13th of October 2023.\r\n\r\nIndividual students are identified using student ID within each college and each academic year. Students can achieve a qualification in more than one course. \r\n\r\nOnly students enrolled in their final year on regulated level 2 courses are included in this analysis. Those in their final year, who have completed the course and subsequently achieved are regarded as “Students achieving qualifications”. \r\n\r\nTo prevent the identification of individuals, figures in the attached tables are rounded to the nearest 5, with 0, 1, 2 rounded to 0.\r\n\r\nFrom academic year 2013/14, ‘regulated enrolments’ at ‘level 3 or below’ are regarded as those on courses that are at and appear on the Register of Regulated Qualifications (RRQ), which contains qualifications on both the Qualifications and Credit Framework and the National Qualifications Framework or part of the Department’s Prescribed List of Approved Qualifications (PLAQ)/Access list).\r\n\r\n“Level” refers to the nationally recognised qualification level of the course.\r\n\r\nAchievements are final year full and partial achievements.\r\n\r\nTransfers are excluded from the analysis.\r\n\r\nWithdrawals are included where there is an achieved outcome.\r\n\r\nIn 2020/21, 2021/22 and 2022/23, where the Outcome code is ‘S’ (COVID affected - outcome deferred to next year), these enrolments are filtered out of all performance analysis, that is Students enrolled in final year and Students achieving qualifications.\r\n\r\nDue to rounding the sum of numbers in each row or column may not match the total shown.\r\n\r\nPercentages are based on unrounded figures and are suppressed if a figure is less than 22.5. Percentages have been rounded to the nearest integer.\r\n\r\nSection 75 category: Age\r\nVariable used: Age\r\nBreakdown available: 19 and under; 20-24; 25+\r\n\r\nAge is calculated at 1st July prior to the start date of enrolment. Where a student has more than one achievement and therefore possibly more than one age calculated, (as the academic year August to July does not quite align with the age taken at 1st July) the youngest age is used in this analysis.\r\n\r\nSection 75 category: Men and women generally\r\nVariable used: Sex\r\nBreakdown available: Female; Male \r\n\r\nThe student provides their sex at the time of enrolment.\r\n\r\nSection 75 category: Marital status\r\nVariable used: Marital status\r\nBreakdown available: Single (never married or never in a legally registered civil partnership); Married or in a legally registered civil partnership; Divorced or formerly in a civil partnership which is now legally dissolved/Separated (but still legally married or still legally in a civil partnership); Widowed or surviving member of a legally registered civil partnership; Unknown\r\n\r\nMarital status is supplied by the student at the time of enrolment.\r\n\r\nSection 75 category: Persons with a disability and persons without\r\nVariable used: Disability\r\nBreakdown available: Disabled; Not Disabled\r\n\r\nInformation on student disability is derived from individuals self-reporting a disability.\r\n\r\nSection 75 category: Religious belief\r\nVariable used: Religious belief\r\nBreakdown available: Catholic; Protestant and other Christian religions; Other; No religion; Not stated\r\n\r\nReligious belief is self-reported by the student at the time of enrolment.\r\n\r\nSection 75 category: Sexual orientation\r\nVariable used: Sexual orientation\r\nBreakdown available: Straight or heterosexual; Gay, lesbian, bisexual or other; Prefer not to say/not stated\r\n\r\nSexual orientation is supplied by the student at the time of enrolment.\r\n\r\nSection 75 category: Persons with dependants and persons without\r\nVariable used: Dependants\r\nBreakdown available: Has dependants; Does not have dependants\r\n\r\n‘With dependants' includes: individuals who have responsibility for the care of: a child(ren); a person with a disability; and/or a dependant elderly person. Dependants is derived from 3 fields: \r\n\r\n1. Dependent Adult field - indicates whether the individual has indicated they have responsibility for one or more Dependent adults.\r\n2. Dependent Children field - indicates whether the individual has indicated they have responsibility for dependent children.\r\n3. Dependant person with a disability field - indicates whether the individual has indicated they have responsibility for one or more persons with a disability.\r\n\r\nSection 75 category: Racial group\r\nVariable used: Ethnic Group\r\nBreakdown available: White; Other; Unknown\r\n\r\nDue to low numbers, students of any other ethnic group than white or unknown have been combined into ‘Other’.\r\n\r\nEthnicity is supplied by the student at the time of enrolment.\r\n\r\nSection 75 category: Political opinion\r\nBreakdown available: These data are not collected by the survey"};
